package _06_strings;

import java.util.HashMap;

public class _10_valid_anagram {
    public static void main(String[] args) {
        String s = "";
        String t = "";

        int sLen = s.length();
        int tLen = t.length();

        if (sLen != tLen) {
            System.out.println("Not anagram");
            System.exit(0);
        }

        HashMap<Character, Integer> sFreq = new HashMap<>();
        HashMap<Character, Integer> tFreq = new HashMap<>();

        for (int index = 0; index < sLen; index++) {
            sFreq.put(s.charAt(index), sFreq.getOrDefault(s.charAt(index), 0) + 1);
            tFreq.put(t.charAt(index), tFreq.getOrDefault(t.charAt(index), 0) + 1);
        }

        System.out.println(sFreq);
        System.out.println(tFreq);

        if (sFreq.size() != tFreq.size()) {
            System.out.println("Not anagram");
            System.exit(0);
        }

        for (char sCh : sFreq.keySet()) {
            int sF = sFreq.getOrDefault(sCh, 0);
            int tF = tFreq.getOrDefault(sCh, 0);
            if (sF != tF) {
                System.out.println("Not anagram");
                System.exit(0);
            }
        }

        System.out.println("Anagram");
    }
}
